sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    try {
        // Require IDP user role
        if (!gs.hasRole('x_146833_idpkiro.user')) {
            response.setStatus(403);
            response.setBody({ error: 'Access denied. IDP user role required.' });
            return;
        }

        var body = request.body.data;
        if (!body || !body.question) {
            response.setStatus(400);
            response.setBody({ error: 'Request body must include a "question" field.' });
            return;
        }

        var ai = new x_146833_idpkiro.IDPAIOrchestrator();
        var result = ai.ask(body.question, gs.getUserID());

        response.setStatus(200);
        response.setBody({ result: result });

    } catch (e) {
        gs.logError('IDP /ai/ask error: ' + e.message, 'IDP-API');
        response.setStatus(500);
        response.setBody({ error: 'Internal server error.' });
    }
})(request, response);
